#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id (POD type)
        stream << packet_id;

        // Write username with length prefix using prefixed adaptor
        stream << hexi::prefixed(username);

        // Write scores count and elements using prefixed adaptor
        stream << hexi::prefixed(scores);

        // Write metadata as null-terminated string using null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer to hold the serialized data
    hexi::buffer buffer;

    // Create a binary_stream object using the buffer
    hexi::binary_stream stream(buffer);

    // Call the serialise method on the packet object with the stream
    packet.serialise(stream);

    // Return the buffer's data as a vector of uint8_t
    return std::vector<uint8_t>(buffer.data(), buffer.data() + buffer.size());
}
```

