#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

void skip_bytes_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::size_t bytes) {
    // Skip the specified number of bytes in the buffer
    buffer.skip(bytes);
}

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
};

MessageHeader read_header_and_skip_body(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // Read the header data
    MessageHeader header;
    buffer.read(&header, sizeof(header));

    // Skip the body data based on the header's length field
    skip_bytes_in_buffer(buffer, header.body_length);

    return header;
}
```

## Explanation:

1. **skip_bytes_in_buffer function**:
   - Uses the `skip` method from `hexi::pmc::buffer_adaptor` to skip the specified number of bytes
   - The `skip` method internally calls `buffer_seek` with `buffer_seek::sk_forward` to advance the read position

2. **read_header_and_skip_body function**:
   - Declares a `MessageHeader` struct to hold the header data
   - Uses the `read` method to read the header data directly into the struct
   - Calls `skip_bytes_in_buffer` to skip the body data using the `body_length` field from the header
   - Returns the populated header struct

Both functions properly utilize the `hexi::pmc` namespace and the provided buffer adaptor methods as specified in the reference materials.

