```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/shared.h>
#include <vector>
#include <cstdint>

bool check_can_write_seek(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    return buffer.can_write_seek();
}

void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, hexi::buffer_seek direction, std::size_t offset) {
    buffer.write_seek(direction, offset);
}

void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    // Save current position by seeking to position 0 and getting the current position
    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);
    auto current_pos = buffer.tell();

    // Write header at position 0
    buffer.write(&header_value, sizeof(header_value));

    // Write some dummy body data (for demonstration)
    std::vector<std::byte> dummy_body(100, std::byte{0});
    buffer.write(dummy_body.data(), dummy_body.size());

    // Seek back to position 0 to update header
    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);

    // Update header with final value
    buffer.write(&header_value, sizeof(header_value));
}
```

## Explanation:

1. **`check_can_write_seek`**: Directly calls the `can_write_seek()` method on the buffer adaptor instance, which returns a boolean indicating if write seeking is supported.

2. **`seek_write_position`**: Calls `write_seek()` with the provided direction and offset parameters, using the `buffer_seek` enum values.

3. **`update_header_at_position`**: 
   - First seeks to position 0 and saves the current position (though in this case we're starting at position 0)
   - Writes the initial header value at position 0
   - Writes some dummy body data to simulate content
   - Seeks back to position 0 using absolute seeking
   - Updates the header with the final value

The implementation follows the exact specifications and uses the correct methods and enums from the reference materials.

